/bin/sh -c 'mkdir -p /root/.cli-proxy-api /CLIProxyAPI/logs; printf "%s\n" "host: \"0.0.0.0\"" "port: 8317" "remote-management:" "  allow-remote: true" "  secret-key: \"$MANAGEMENT_KEY\"" "  disable-control-panel: false" "auth-dir: \"/root/.cli-proxy-api\"" "api-keys:" "  - \"$API_KEY\"" "debug: false" "logging-to-file: false" "usage-statistics-enabled: false" "commercial-mode: true" "request-retry: 2" "max-retry-credentials: 3" "max-retry-interval: 20" "routing:" "  strategy: \"round-robin\"" "session-affinity: false" "ws-auth: false" "enable-gemini-cli-endpoint: false" "nonstream-keepalive-interval: 0" > /CLIProxyAPI/config.yaml; exec /CLIProxyAPI/CLIProxyAPI'
